const firstItem = $input.all()[0].json;
const stateEncoded = firstItem.query.state;

// Check if state is actually provided
if (!stateEncoded || stateEncoded === 'undefined' || stateEncoded === 'null') {
    throw new Error('No valid state parameter found. State value: ' + stateEncoded);
}

// Decode state
try {
    // Try base64url decoding (URL-safe base64)
    const stateJson = Buffer.from(stateEncoded, 'base64url').toString('utf-8');
    const stateData = JSON.parse(stateJson);

    const sessionId = stateData.sessionId || '';
    const csrfToken = stateData.csrf || '';
    const timestamp = stateData.timestamp || '';

    if (!sessionId) {
        throw new Error('No sessionId found in decoded state');
    }

    console.log(`✅ SessionId extracted: ${sessionId}`);

    // Return modified item
    return [{
        json: {
            ...firstItem,
            sessionId: sessionId,
            csrfToken: csrfToken,
            stateTimestamp: timestamp
        }
    }];

} catch (error) {
    // If base64url fails, try regular base64
    try {
        const stateJson = Buffer.from(stateEncoded, 'base64').toString('utf-8');
        const stateData = JSON.parse(stateJson);

        const sessionId = stateData.sessionId || '';
        const csrfToken = stateData.csrf || '';
        const timestamp = stateData.timestamp || '';

        if (!sessionId) {
            throw new Error('No sessionId found in decoded state');
        }

        console.log(`✅ SessionId extracted: ${sessionId}`);

        return [{
            json: {
                ...firstItem,
                sessionId: sessionId,
                csrfToken: csrfToken,
                stateTimestamp: timestamp
            }
        }];

    } catch (innerError) {
        throw new Error(`Failed to decode state. Original value: "${stateEncoded}". Error: ${error.message}`);
    }
}

const mailboxSettings = $input.first().json;
const tokenData = $('Request_Tokens1').first().json;
const windowsTz = mailboxSettings.timeZone || 'Eastern Standard Time';

const windowsToIana = {
  "Eastern Standard Time": "America/New_York",
  "Pacific Standard Time": "America/Los_Angeles",
  "Central Standard Time": "America/Chicago",
  "Mountain Standard Time": "America/Denver"
};

const ianaTz = windowsToIana[windowsTz] || 'America/New_York';
console.log(`✅ User timezone: ${windowsTz} → ${ianaTz}`);

return {
  json: {
    ...tokenData,
    timezone: ianaTz,
    windowsTimezone: windowsTz,
    language: mailboxSettings.language?.locale || 'en-US'
  }
};

const userData = $('Mapping_Content1').first().json;
const webhookUrl = $vars.Email_Categorization_Webhook_URL || '';

return [{
  json: {
    user_id: userData.userId,  // ✅ CHANGED: Use Microsoft's userId instead of timestamp
    user_email: userData.employeeEmail,
    user_name: userData.employeeName,
    access_token: userData.accessToken,
    refresh_token: userData.refreshToken,
    token_expires_at: userData.expiresAt,
    token_expires_at_unix: userData.expiresAtUnix,
    last_refreshed: userData.lastRefreshed,
    timezone: userData.timezone,
    webhook_url: webhookUrl,
    is_active: true
  }
}];

// Node: "Check_Categories_And_Extract_Email"

const data = $input.first().json;

// Extract email from @odata.context
// Format: "https://graph.microsoft.com/v1.0/$metadata#users('email%40domain.com')/outlook/masterCategories"
const odataContext = data['@odata.context'] || '';
let userEmail = '';

// Extract email using regex
const emailMatch = odataContext.match(/users\('([^']+)'\)/);
if (emailMatch && emailMatch[1]) {
  // Decode URL-encoded email (%40 → @)
  userEmail = decodeURIComponent(emailMatch[1]);
  console.log(`✅ Extracted email: ${userEmail}`);
} else {
  console.warn(`⚠️ Could not extract email from: ${odataContext}`);
}

// Check which categories need to be created
const requiredCategories = [
  { displayName: 'URGENT', color: 'preset0' },
  { displayName: 'TO_REPLY', color: 'preset2' },
  { displayName: 'ACTION_REQUIRED', color: 'preset4' },
  { displayName: 'MEETING_SUMMARY', color: 'preset8' },
  { displayName: 'JAGGAER', color: 'preset9' },
  { displayName: 'FYI', color: 'preset5' },
  { displayName: 'PROMOTIONAL', color: 'preset13' }
];

const existingCategories = data.value || [];
const existingSet = new Set(existingCategories.map(cat => cat.displayName.toUpperCase().trim()));

const categoriesToCreate = requiredCategories.filter(
  cat => !existingSet.has(cat.displayName.toUpperCase().trim())
);

console.log(`📊 Categories check for ${userEmail}:`);  // ✅ Fixed
console.log(`   Existing: ${existingCategories.length}`);  // ✅ Fixed
console.log(`   Required: ${requiredCategories.length}`);  // ✅ Fixed
console.log(`   To create: ${categoriesToCreate.length}`);  // ✅ Fixed

return [{
  json: {
    userEmail: userEmail,  // ✅ Added email
    needsCreation: categoriesToCreate.length > 0,
    categoriesToCreate: categoriesToCreate,
    existingCategoriesCount: existingCategories.length
  }
}];

const code = $input.item.json.query.code;
const sessionId = $input.item.json.sessionId;
const csrfToken = $input.item.json.csrfToken;

if (!code) {
  throw new Error('No authorization code received');
}

return {
  json: {
    code: code,
    sessionId: sessionId,
    csrfToken: csrfToken
  }
};

const tokenData = $input.first().json;

// Extract tokens
const accessToken = tokenData.access_token || '';
const refreshToken = tokenData.refresh_token || '';
const idToken = tokenData.id_token || '';
const tokenType = tokenData.token_type || 'Bearer';
const expiresIn = tokenData.expires_in || 3600;
const scope = tokenData.scope || '';
const sessionId = tokenData.sessionId || '';
const timezone = tokenData.timezone || '';

if (!accessToken || !idToken) {
    throw new Error('Missing required tokens');
}

console.log(`✅ Received fresh tokens from Microsoft (expires_in: ${expiresIn}s)`);

// Decode JWT to get user info
try {
    // Split JWT and get payload (middle part)
    const jwtParts = idToken.split('.');
    if (jwtParts.length !== 3) {
        throw new Error('Invalid JWT format');
    }

    const payloadEncoded = jwtParts[1];
    const payloadDecoded = Buffer.from(payloadEncoded, 'base64url').toString('utf-8');
    const payload = JSON.parse(payloadDecoded);

    // Extract user information
    const employeeName = payload.name || '';
    const employeeEmail = payload.email || payload.preferred_username || payload.upn || '';
    const userId = payload.oid || payload.sub || '';

    if (!userId) {
        throw new Error('No userId found in JWT');
    }

    console.log(`✅ User authenticated: ${employeeName} (${employeeEmail})`);

    // Calculate token expiration
    const currentTime = Math.floor(Date.now() / 1000);
    const expiresAtUnix = currentTime + expiresIn;
    const expiresAtIso = new Date(expiresAtUnix * 1000).toISOString();
    const lastRefreshedIso = new Date(currentTime * 1000).toISOString();

    console.log(`✅ Token expiry: ${expiresAtIso}`);

    // Return structured data
    return [{
        json: {
            sessionId: sessionId,
            userId: userId,
            employeeEmail: employeeEmail,
            employeeName: employeeName,
            accessToken: accessToken,
            refreshToken: refreshToken,
            timezone: timezone,
            tokenType: tokenType,
            scope: scope,
            expiresIn: expiresIn,
            expiresAt: expiresAtIso,
            expiresAtUnix: expiresAtUnix,
            lastRefreshed: lastRefreshedIso,
            authProvider: 'microsoft'
        }
    }];

} catch (error) {
    throw new Error(`Failed to decode JWT: ${error.message}`);
}

// Node: "Filter_User_Subscriptions"

const webhookUrl = $vars.Email_Categorization_Webhook_URL;
const allSubs = $input.first().json.value || [];

// ✅ Get user email from Check_Categories node
const userEmail = $('Check_Categories').first().json.userEmail;

if (!userEmail) {
  throw new Error('No user email found from Check_Categories node');
}

// ✅ FIXED: Get user_id from Mapping_Content1 (the source of truth)
const userId = $('Mapping_Content1').first().json.userId;

if (!userId) {
  throw new Error('No userId found from Mapping_Content1 node');
}

console.log(`📊 Total subscriptions in account: ${allSubs.length}`);
console.log(`👤 Looking for subscriptions for user: ${userEmail} (ID: ${userId})`);

// Filter: Our webhook + this user
const userSubs = allSubs.filter(sub => {
  const matchesWebhook = sub.notificationUrl === webhookUrl;
  const matchesUser = sub.resource && sub.resource.toLowerCase().includes(userEmail.toLowerCase());
  return matchesWebhook && matchesUser;
});

console.log(`🎯 Found ${userSubs.length} subscription(s) for ${userEmail}`);

if (userSubs.length === 0) {
  console.log(`✅ No existing subscriptions - will create new one`);
  return [{ 
    json: { 
      _noSubscriptions: true, 
      user_email: userEmail,
      user_id: userId,  // ✅ Now using Microsoft's stable userId
      access_token: $('Mapping_Content1').first().json.accessToken 
    } 
  }];  
}

console.log(`🗑️  Will delete ${userSubs.length} subscription(s):`);
userSubs.forEach((sub, index) => {
  console.log(`   ${index + 1}. ID: ${sub.id}`);
  console.log(`      Expires: ${sub.expirationDateTime}`);
});

// Return each subscription as a separate item for the loop
return userSubs.map(sub => ({
  json: {
    _noSubscriptions: false, 
    subscription_id: sub.id,
    subscription_resource: sub.resource,
    subscription_expires: sub.expirationDateTime,
    user_email: userEmail,
    user_id: userId,  // ✅ Now using Microsoft's stable userId
    access_token: $('Mapping_Content1').first().json.accessToken
  }
}));

// Node: Prepare_Subscription_Data
// This runs AFTER all subscriptions are deleted

// Get the original data from Filter_User_Subscriptions
const originalData = $('Filter_User_Subscriptions').first().json;

console.log('✅ All subscriptions deleted, preparing to create new one');
console.log(`   User: ${originalData.user_email}`);
console.log(`   User ID: ${originalData.user_id}`);

return [{
  json: {
    user_email: originalData.user_email,
    user_id: originalData.user_id,
    access_token: originalData.access_token,
    _noSubscriptions: true  // Mark as ready for creation
  }
}];

