=<!DOCTYPE html>
<html>
<head>
  <title>Redirecting...</title>
  <meta charset="UTF-8">
  <meta name="viewport" content="width=device-width, initial-scale=1.0">
  <style>
    body {
      font-family: 'Segoe UI', sans-serif;
      display: flex;
      justify-content: center;
      align-items: center;
      min-height: 100vh;
      background: linear-gradient(135deg, #2C5F5F 0%, #1a4444 100%);
      margin: 0;
    }
    .loading {
      text-align: center;
      color: white;
    }
    .loading h2 {
      margin-bottom: 20px;
    }
    .spinner {
      border: 4px solid rgba(255,255,255,0.3);
      border-top: 4px solid #F39C12;
      border-radius: 50%;
      width: 50px;
      height: 50px;
      animation: spin 1s linear infinite;
      margin: 0 auto;
    }
    @keyframes spin {
      0% { transform: rotate(0deg); }
      100% { transform: rotate(360deg); }
    }
  </style>
</head>
<body>
  <div class="loading">
    <div class="spinner"></div>
    <h2>Setting up your account...</h2>
  </div>

  <script>
    const userData = {
      userId: '{{ $json.sessionId }}',
      userEmail: '{{ $json.userEmail }}',
      userName: '{{ $json.userName }}',
      userId : '{{ $json.userId }}',
    };

    const baseUrl = window.location.origin;
    const preferenceUrl = `${baseUrl}/webhook/preference?userId=${encodeURIComponent(userData.userId)}&userEmail=${encodeURIComponent(userData.userEmail)}&userName=${encodeURIComponent(userData.userName)}`;

    console.log('Redirecting to:', preferenceUrl);

    // Immediate redirect
    window.location.href = preferenceUrl;
  </script>
</body>
</html>
